(function(){
  var c = drawingContext,
      w = dimensionContext.width,
      h = dimensionContext.height;
  var imgData = c.getImageData(0,0,w,h);
  var data = imgData.data;
  var depthT = state.depthT||0;
  var burstAmt = state.colorBurstAmt||0;
  for(var y=0;y<h;y++){
    for(var x=0;x<w;x++){
      var idx=(y*w+x)*4;
      var n = R.dec();
      var grain = (n*255)|0;
      var d = 0.4 + 0.6*Math.sin((y/h*6.283)+(depthT*3.14159));
      var v = grain*d;
      var r=v,g=v,b=v;
      if(burstAmt>0){
        var hue = (x/w*360 + y/h*90 + (state.t||0)*0.5)|0;
        var sat = 50+burstAmt*50;
        var light = 35+burstAmt*35;
        var a = sat/100, l = light/100;
        var k = (1-Math.abs(2*l-1))*a;
        var kk=hue/60;
        var xC=k*(1-Math.abs(kk%2-1));
        var m=l-k/2;
        var rr,gg,bb;
        if(kk<1){rr=k;gg=xC;bb=0;}
        else if(kk<2){rr=xC;gg=k;bb=0;}
        else if(kk<3){rr=0;gg=k;bb=xC;}
        else if(kk<4){rr=0;gg=xC;bb=k;}
        else if(kk<5){rr=xC;gg=0;bb=k;}
        else{rr=k;gg=0;bb=xC;}
        r=255*(rr+m);
        g=255*(gg+m);
        b=255*(bb+m);
      }
      data[idx]=r;
      data[idx+1]=g;
      data[idx+2]=b;
      data[idx+3]=255;
    }
  }
  c.putImageData(imgData,0,0);
})();
